class Solution {
public:
    vector<int> popcountDepth(vector<long long>& nums, vector<vector<long long>>& queries) {
        vector<int> depth(1e5 + 1);
        for (int i = 1; i <= 1e5; ++i) {
            int x = i, d = 0;
            while (x != 1) {
                x = __builtin_popcount(x);
                ++d;
            }
            depth[i] = d;
        }

        vector<int> res;
        for (auto& q : queries) {
            if (q[0] == 1) {
                int l = q[1], r = q[2], k = q[3], cnt = 0;
                for (int i = l; i <= r; ++i) {
                    cnt += depth[nums[i]] == k;
                }
                res.push_back(cnt);
            } else {
                nums[q[1]] = q[2];
            }
        }
        return res;
    }
};
